#include<bits/stdc++.h>
using namespace std;
long long n,pl[1010],pr[1010],l[1010],r[1010],h[1010],dis[2010],s,t;
bool vis[2010];
struct node
{
    int l,r,h,id;
    bool operator<(const node&b)const
    {
        return h>b.h;
    }
}a[2010];
vector<pair<long long,long long>> mp[2010];
long long L(long long x)
{
    return x*2-1;
}
long long R(long long x)
{
    return x*2;
}
void dijkstra()
{
    memset(dis,0x3f,sizeof(dis));
    dis[L(s)]=0;
    priority_queue<pair<long long,long long>> q;
    q.push({0,L(s)});
    // q.push({0,R(s)});
    while(!q.empty())
    {
        long long t=q.top().second;
        q.pop();
        if(vis[t])
        {
            continue;
        }
        vis[t]=true;
        for(auto i:mp[t])
        {
            long long v=i.first,val=i.second;
            if(dis[v]>dis[t]+val)
            {
                dis[v]=dis[t]+val;
                q.push({-dis[v],v});
            }
        }
    }
}
int main()
{
    scanf("%lld%lld%lld",&n,&s,&t);
    if(s==t)
    {
        printf("0");
        return 0;
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld%lld%lld",&a[i].l,&a[i].r,&a[i].h);
        a[i].id=i;
    }
    sort(a+1,a+1+n);
    for(int i=1;i<=n;i++)
    {
        if(a[i].id==s)
        {
            s=i;
            break;
        }
    }
    for(int i=1;i<=n;i++)
    {
        if(a[i].id==t)
        {
            t=i;
            break;
        }
    }
    for(long long i=1;i<=n;i++)
    {
        l[i]=a[i].l,r[i]=a[i].r,h[i]=a[i].h;
    }
    for(long long i=1;i<=n;i++)
    {
        bool flagl=false,flagr=false;
        for(long long j=1;j<=n;j++)
        {
            if(h[i]>h[j])
            {
                if(!flagl&&l[j]<=l[i]&&l[i]<=r[j])
                {
                    pl[i]=j;
                    flagl=true;
                    mp[L(i)].push_back({L(j),h[i]-h[j]+(l[i])-l[j]});
                    // printf("add(L(%lld),L(%lld),%lld)\n",i,j,h[i]-h[j]+(l[i]-1)-l[j]);
                    mp[L(i)].push_back({R(j),h[i]-h[j]+r[j]-(l[i])});
                    // printf("add(L(%lld),R(%lld),%lld)\n",i,j,h[i]-h[j]+r[j]-(l[i]-1));
                }
                if(!flagr&&l[j]<=r[i]&&r[i]<=r[j])
                {
                    pr[i]=j;
                    flagr=true;
                    mp[R(i)].push_back({L(j),h[i]-h[j]+(r[i])-l[j]});
                    // printf("add(R(%lld),L(%lld),%lld)\n",i,j,h[i]-h[j]+(r[i]+1)-l[j]);
                    mp[R(i)].push_back({R(j),h[i]-h[j]+r[j]-(r[i])});
                    // printf("add(R(%lld),R(%lld),%lld)\n",i,j,h[i]-h[j]+r[j]-(r[i]+1));
                }
            }
        }
        // printf("pl[%lld]=%lld pr[%lld]=%lld\n",i,pl[i],i,pr[i]);
        mp[L(i)].push_back({R(i),r[i]-l[i]});
        mp[R(i)].push_back({L(i),r[i]-l[i]});
    }
    dijkstra();
    long long ans=LLONG_MAX;
    for(long long i=1;i<=n;i++)if(i!=t&&h[i]>h[t])
    {
        if(pl[i]==t&&l[t]<=l[i]&&l[i]<=r[t])
        {
            ans=min(ans,dis[L(i)]+h[i]-h[t]);
        }
        if(pr[i]==t&&l[t]<=r[i]&&r[i]<=r[t])
        {
            ans=min(ans,dis[R(i)]+h[i]-h[t]);
        }
    }
    if(ans>1e18)
    {
        ans=-1;
    }
    printf("%lld\n",ans);
    return 0;
}
